#include "max17048.h"
#include <Wire.h>
#include <Adafruit_MAX1704X.h>
static Adafruit_MAX17048 fg;
static float _v=0,_pct=0,_rate=0;static unsigned long _l=0;
void max17048_setup(){Wire.begin();if(!fg.begin()){Serial.println("[max17048] Fail!");return;}Serial.println("[max17048] OK");}
void max17048_loop(){if(millis()-_l<5000)return;_l=millis();_v=fg.cellVoltage();_pct=fg.cellPercent();_rate=fg.chargeRate();}
float max17048_voltage(){return _v;}
float max17048_percent(){return _pct;}
float max17048_charge_rate(){return _rate;}
